module top_module(input_data, In, Reset, Clk, Load, Increment);parameter SIZE=4;
input Increment;
input [SIZE-1:0]In;
input Reset, Clk, Load;
output [SIZE-1:0]input_data;
reg [SIZE-1:0]input_data;

always @ (posedge Clk or negedge Reset)
	if(!Reset)
		input_data = 0;
	else 
	 begin
     if (Increment) 
	   	input_data = input_data +1;
	 if(Load)
			input_data = In;
      end
endmodule
